scwin.f_EvidEnable = function (on) {
    if (on) {
        $c.gus.cfEnableObjects([tbl_evidence]);
        scwin.f_EvidHeaderCreate();
        scwin.f_PrepayHeaderCreate();
    } else {
        dma_evidence.undo();
        ds_provHeader.undoAll();
        ds_prov.undoAll();
        $c.gus.cfDisableObjects([tbl_evidence]);
    }
    $c.gus.cfDisableObjects([ed_supplierNm, ed_vatDeclarAcctDeptNm, ed_reqAmt
        , ed_vatSpplierCrn, ed_clntNm, ed_cardNm]);

}

